        '<div class="badge ' + s.badgeClass + ' text-white mx-1"><i class="fas ' + s.iconClass + ' icon-background"></i> ' + s.displayText + '</div>';
    }

    PTT_UTILS.getCurrentLocation()
      .then(function (l) {
