      /* Loading / Error */
      ".opw-modal-loading{padding:40px 20px;text-align:center;color:#94a3b8;font-size:13px;}" +
      ".opw-modal-loading i{margin-right:6px;}" +
      ".opw-modal-error{padding:30px 20px;text-align:center;color:#ef4444;font-size:12px;}" +
      ".opw-modal-error i{margin-right:4px;}" +

      /* ─── Responsive ─── */
      "@media(max-width:480px){" +
        "#oil-price-widget{top:8px;left:8px;}" +
        ".opw-chip{padding:5px 10px 5px 6px;gap:5px;}" +
        ".opw-chip-icon{width:24px;height:24px;font-size:10px;}" +
        ".opw-chip-text{font-size:10px;}" +
        ".opw-chip-sub{font-size:7px;}" +
        ".opw-modal{max-width:340px;border-radius:20px;}" +
        ".opw-modal-header{padding:16px 18px 14px;}" +
        ".opw-modal-icon{width:30px;height:30px;font-size:13px;border-radius:10px;}" +
        ".opw-modal-title{font-size:14px;}" +
        ".opw-modal-body{padding:12px 14px 6px;}" +
        ".opw-fuel-card{padding:12px 14px;gap:12px;margin-bottom:8px;border-radius:14px;}" +
        ".opw-fuel-badge{width:38px;height:38px;border-radius:12px;font-size:14px;}" +
        ".opw-fuel-name{font-size:12px;}" +
        ".opw-price-value{font-size:16px;}" +
        ".opw-fuel-prices{gap:10px;}" +
      "}";

    document.head.appendChild(s);
  }

  // ── Build floating chip ───────────────────────────────────
  function createWidget() {
    if (widgetEl) return;

    widgetEl = document.createElement("div");
    widgetEl.id = "oil-price-widget";
    widgetEl.innerHTML =
      '<div class="opw-chip" id="opw-chip">' +
        '<div class="opw-chip-icon"><i class="fas fa-gas-pump"></i></div>' +
        '<div>' +
          '<span class="opw-chip-text">Oil Prices</span>' +
          '<span class="opw-chip-sub">Tap to view</span>' +
        '</div>' +
        '<div class="opw-chip-dot"></div>' +
      '</div>';
    document.body.appendChild(widgetEl);

    // Build the modal overlay
    modalEl = document.createElement("div");
    modalEl.className = "opw-overlay";
    modalEl.id = "opw-overlay";
    modalEl.innerHTML =
      '<div class="opw-modal" id="opw-modal">' +
        '<div class="opw-modal-header">' +
          '<div class="opw-modal-header-top">' +
            '<div class="opw-modal-title-wrap">' +
              '<div class="opw-modal-icon"><i class="fas fa-gas-pump"></i></div>' +
              '<div>' +
                '<div class="opw-modal-title">Live Oil Prices</div>' +
                '<div class="opw-modal-subtitle">PTT Cambodia · Updated live</div>' +
              '</div>' +
            '</div>' +
            '<button class="opw-modal-close" id="opw-close"><i class="fas fa-times"></i></button>' +
          '</div>' +
        '</div>' +
        '<div class="opw-modal-body" id="opw-body">' +
          '<div class="opw-modal-loading"><i class="fas fa-spinner fa-spin"></i> Loading prices…</div>' +
        '</div>' +
        '<div class="opw-modal-footer" id="opw-footer">' +
          '<i class="fas fa-clock"></i> <span id="opw-time">—</span>' +
        '</div>' +
      '</div>';
    document.body.appendChild(modalEl);

    // Open modal on chip click
    document.getElementById("opw-chip").addEventListener("click", function () {
      modalEl.classList.add("opw-open");
    });

    // Close modal
    document.getElementById("opw-close").addEventListener("click", function (e) {
      e.stopPropagation();
      modalEl.classList.remove("opw-open");
    });

    // Close on overlay click
    modalEl.addEventListener("click", function (e) {
      if (e.target === modalEl) {
        modalEl.classList.remove("opw-open");
      }
    });
  }

  // ── Render prices ─────────────────────────────────────────
  function renderPrices(data) {
    var nextSignature = JSON.stringify(data || {});
    if (lastRenderedSignature === nextSignature) {
      return;
    }

    lastData = data;
    lastRenderedSignature = nextSignature;
    var body = document.getElementById("opw-body");
    if (!body) return;

    var prices = data.prices || {};
    var updatedAt = data.updated_at || "";

    var timeStr = "";
    if (updatedAt) {
      try {
        var d = new Date(updatedAt);
        timeStr = d.toLocaleDateString("en-US", {
          day: "numeric", month: "short", year: "numeric",
          hour: "2-digit", minute: "2-digit", hour12: true,
          timeZone: "Asia/Phnom_Penh"
        });
      } catch (e) {
        timeStr = updatedAt;
      }
    }

    // Update chip subtitle with first price
    var firstPrice = prices["ULR 91"];
    var chipSub = widgetEl ? widgetEl.querySelector(".opw-chip-sub") : null;
    if (firstPrice && chipSub) {
      chipSub.textContent = "ULR $" + Number(firstPrice.dollar).toFixed(2);
    }

    // Update time in footer
    var timeEl = document.getElementById("opw-time");
    if (timeEl) timeEl.textContent = timeStr || "—";

    // Render fuel cards
    var html = "";
    var fuelOrder = ["ULR 91", "ULG 95", "HSD"];
    fuelOrder.forEach(function (key) {
      var p = prices[key];
      if (!p) return;
      var cfg = FUEL_CONFIG[key] || {
        color: "#666", gradient: "linear-gradient(135deg,#999,#666)",
        bg: "rgba(100,100,100,.06)", icon: "fa-gas-pump",
        label: key, labelEn: key, symbol: "?"
      };

      html +=
        '<div class="opw-fuel-card" style="background:' + cfg.bg + ';">' +
          '<div class="opw-fuel-badge" style="background:' + cfg.gradient + ';">' +
            '<i class="fas ' + cfg.icon + '"></i>' +
          '</div>' +
          '<div class="opw-fuel-info">' +
            '<div class="opw-fuel-name">' + cfg.labelEn + '</div>' +
            '<div class="opw-fuel-name-kh">' + cfg.label + '</div>' +
            '<div class="opw-fuel-prices">' +
              '<div class="opw-price-tag opw-price-dollar">' +
                '<span class="opw-price-value">$' + Number(p.dollar).toFixed(2) + '</span>' +
                '<span class="opw-price-currency">USD</span>' +
              '</div>' +
              '<div class="opw-price-tag opw-price-riel">' +
                '<span class="opw-price-value">៛' + Number(p.riel).toLocaleString() + '</span>' +
                '<span class="opw-price-currency">KHR</span>' +
              '</div>' +
            '</div>' +
          '</div>' +
        '</div>';
    });

    body.innerHTML = html;
  }

  function renderError() {
    var body = document.getElementById("opw-body");
    if (!body || lastData) return;
    body.innerHTML =
      '<div class="opw-modal-error">' +
        '<i class="fas fa-exclamation-triangle"></i> Unable to load prices' +
      '</div>';
    var chipSub = widgetEl ? widgetEl.querySelector(".opw-chip-sub") : null;
    if (chipSub) chipSub.textContent = "Tap to retry";
  }

  // ── Fetch data ────────────────────────────────────────────
  function buildFreshUrl(url) {
    var sep = url.indexOf("?") === -1 ? "?" : "&";
    return url + sep + "_ts=" + Date.now();
  }

  function fetchFromUrl(url) {
    return fetch(buildFreshUrl(url), {
      mode: "cors",
      headers: {
        "Accept": "application/json"
      }
    })
      .then(function (res) {
        if (!res.ok) throw new Error("HTTP " + res.status);
        return res.json();
      });
  }

  function getRefreshInterval() {
    return document.hidden ? HIDDEN_REFRESH_INTERVAL : VISIBLE_REFRESH_INTERVAL;
  }

  function stopAutoRefresh() {
    if (refreshTimer) {
      clearTimeout(refreshTimer);
      refreshTimer = null;
    }
  }

  function scheduleNextRefresh(delay) {
    stopAutoRefresh();
    refreshTimer = setTimeout(function () {
      fetchPrices().finally(function () {
        scheduleNextRefresh(getRefreshInterval());
      });
    }, Math.max(1000, delay || getRefreshInterval()));
  }

  function startAutoRefresh() {
    scheduleNextRefresh(getRefreshInterval());
  }

  function fetchPrices() {
    if (activeFetchPromise) {
      return activeFetchPromise;
    }

    activeFetchPromise = fetchFromUrl(API_URL)
      .then(function (json) {
        if (json.success && json.data) {
          renderPrices(json.data);
          return json.data;
        } else {
          renderError();
          throw new Error("Invalid oil price response.");
        }
      })
      .catch(function (err) {
        console.error("Oil price fetch error:", err);
        renderError();
        throw err;
      })
      .finally(function () {
        activeFetchPromise = null;
      });

    return activeFetchPromise;
  }

  function refresh(options) {
    var settings = options || {};
    if (settings.restartTimer !== false) {
      startAutoRefresh();
    }
    return fetchPrices();
  }

  function handleVisibilityChange() {
    if (document.hidden) {
      startAutoRefresh();
      return Promise.resolve();
    }
    return refresh({ restartTimer: true }).catch(function () {
      return null;
    });
  }

  // ── Public ────────────────────────────────────────────────
  function init() {
    injectCSS();
    createWidget();
    refresh({ restartTimer: false }).catch(function () {
      return null;
    });
    startAutoRefresh();
  }

  return {
    init: init,
    refresh: refresh,
    handleVisibilityChange: handleVisibilityChange,
    stopAutoRefresh: stopAutoRefresh,
  };
})();

/**
 * ============================================================
 *  PTT Station Map — Route Service (Bing Maps)
 *  Depends on: config.js
 * ============================================================
 */
var RouteService = (function () {
  "use strict";

  var TIMEOUT_MS = 8000;

  function _buildUrl(sLat, sLng, eLat, eLng) {
    return (
      "https://dev.virtualearth.net/REST/V1/Routes/Driving" +
      "?wp.0=" + sLat + "," + sLng +
      "&wp.1=" + eLat + "," + eLng +
      "&optmz=timeWithTraffic&key=" + PTT_CONFIG.BING_MAPS_KEY
    );
  }

  function _fetchWithTimeout(url) {
    return new Promise(function (resolve, reject) {
      var timer = setTimeout(function () {
        reject(new Error("Route request timed out"));
      }, TIMEOUT_MS);

      fetch(url)
        .then(function (r) {
          clearTimeout(timer);
          if (!r.ok) throw new Error("HTTP " + r.status);
          return r.json();
        })
        .then(resolve)
        .catch(function (err) {
          clearTimeout(timer);
          reject(err);
        });
    });
  }

  function _parseRoute(data) {
    if (
      !data ||
      !data.resourceSets ||
      !data.resourceSets[0] ||
      !data.resourceSets[0].resources ||
      data.resourceSets[0].resources.length === 0
    ) {
      throw new Error("No route found");
    }
    return data.resourceSets[0].resources[0];
  }

  /** @returns {Promise<{distance: string, travelTime: string}>} */
  function getRoute(startLat, startLng, endLat, endLng) {
    return _fetchWithTimeout(_buildUrl(startLat, startLng, endLat, endLng))
      .then(function (data) {
        var route = _parseRoute(data);
        var km = route.travelDistance;
        var secs = route.travelDurationTraffic || route.travelDuration || 0;
        var mins = secs / 60;
        return {
          distance: km.toFixed(1) + " km",
          travelTime: Math.floor(mins / 60) + " hr " + Math.round(mins % 60) + " min",
        };
      });
  }

  /** @returns {Promise<string>} distance in km */
  function getDistance(startLat, startLng, endLat, endLng) {
    return _fetchWithTimeout(_buildUrl(startLat, startLng, endLat, endLng))
      .then(function (data) {
        var route = _parseRoute(data);
        return route.travelDistance.toFixed(1);
      });
  }

  return { getRoute: getRoute, getDistance: getDistance };
})();

/**
 * ============================================================
 *  PTT Station Map — Route Service
 *  Primary: OSRM (free, no key needed)
 *  Fallback: Bing Maps (if key is valid)
 *  Last resort: straight-line estimate
 *  Depends on: config.js
 * ============================================================
 */
var RouteService = (function () {
  "use strict";

  var TIMEOUT_MS = 6000;
  var AVG_SPEED_KMH = 45; // average Cambodia driving speed for estimate

  // ── Shared helpers ────────────────────────────────────────

  function _fetchWithTimeout(url) {
    return new Promise(function (resolve, reject) {
      var timer = setTimeout(function () {
        reject(new Error("Route request timed out"));
      }, TIMEOUT_MS);

      fetch(url)
        .then(function (r) {
          clearTimeout(timer);
          if (!r.ok) throw new Error("HTTP " + r.status);
          return r.json();
        })
        .then(resolve)
        .catch(function (err) {
          clearTimeout(timer);
          reject(err);
        });
    });
  }

  function _formatTime(totalMinutes) {
    var hrs = Math.floor(totalMinutes / 60);
    var mins = Math.round(totalMinutes % 60);
    if (hrs > 0) {
      return hrs + " hr " + mins + " min";
    }
    return mins + " min";
  }

  // ── OSRM (free, no API key) ───────────────────────────────

  function _osrmUrl(sLat, sLng, eLat, eLng) {
    return (
      "https://router.project-osrm.org/route/v1/driving/" +
      sLng + "," + sLat + ";" + eLng + "," + eLat +
      "?overview=false"
    );
  }

  function _osrmRoute(startLat, startLng, endLat, endLng) {
    return _fetchWithTimeout(_osrmUrl(startLat, startLng, endLat, endLng))
      .then(function (data) {
        if (!data || data.code !== "Ok" || !data.routes || !data.routes[0]) {
          throw new Error("OSRM: no route");
        }
        var r = data.routes[0];
        var km = r.distance / 1000;       // meters → km
        var mins = r.duration / 60;        // seconds → minutes
        return {
          distance: km.toFixed(1) + " km",
          travelTime: _formatTime(mins),
        };
      });
  }

  function _osrmDistance(startLat, startLng, endLat, endLng) {
    return _fetchWithTimeout(_osrmUrl(startLat, startLng, endLat, endLng))
      .then(function (data) {
        if (!data || data.code !== "Ok" || !data.routes || !data.routes[0]) {
          throw new Error("OSRM: no route");
        }
        return (data.routes[0].distance / 1000).toFixed(1);
      });
  }

  // ── Bing Maps (fallback, needs valid key) ─────────────────

  function _bingUrl(sLat, sLng, eLat, eLng) {
    return (
      "https://dev.virtualearth.net/REST/V1/Routes/Driving" +
      "?wp.0=" + sLat + "," + sLng +
      "&wp.1=" + eLat + "," + eLng +
      "&optmz=timeWithTraffic&key=" + PTT_CONFIG.BING_MAPS_KEY
    );
  }

  function _bingRoute(startLat, startLng, endLat, endLng) {
    return _fetchWithTimeout(_bingUrl(startLat, startLng, endLat, endLng))
      .then(function (data) {
        if (
          !data || !data.resourceSets || !data.resourceSets[0] ||
          !data.resourceSets[0].resources || data.resourceSets[0].resources.length === 0
        ) {
          throw new Error("Bing: no route");
        }
        var res = data.resourceSets[0].resources[0];
        var km = res.travelDistance;
        var secs = res.travelDurationTraffic || res.travelDuration || 0;
        return {
          distance: km.toFixed(1) + " km",
          travelTime: _formatTime(secs / 60),
        };
      });
  }

  // ── Public API: try OSRM → Bing → estimate ───────────────

  function getRoute(startLat, startLng, endLat, endLng) {
    return _osrmRoute(startLat, startLng, endLat, endLng)
      .catch(function () {
        return _bingRoute(startLat, startLng, endLat, endLng);
      });
  }

  function getDistance(startLat, startLng, endLat, endLng) {
    return _osrmDistance(startLat, startLng, endLat, endLng)
      .catch(function () {
        return _fetchWithTimeout(_bingUrl(startLat, startLng, endLat, endLng))
          .then(function (data) {
            if (
              !data || !data.resourceSets || !data.resourceSets[0] ||
              !data.resourceSets[0].resources || data.resourceSets[0].resources.length === 0
            ) {
              throw new Error("Bing: no route");
            }
            return data.resourceSets[0].resources[0].travelDistance.toFixed(1);
          });
      });
  }

  /** Instant estimate from straight-line distance (no API call) */
  function estimateFromDistance(km) {
    var mins = (km / AVG_SPEED_KMH) * 60;
    return {
      distance: "~" + Number(km).toFixed(1) + " km",
      travelTime: "~" + _formatTime(mins),
    };
  }

  return {
    getRoute: getRoute,
    getDistance: getDistance,
    estimateFromDistance: estimateFromDistance,
  };
})();

/**
 * ============================================================
 *  PTT Station Map — Shared Utilities
 *  Pure helper functions used across all modules.
 *  Depends on: config.js
 * ============================================================
 */
var PTT_UTILS = (function () {
  "use strict";

  var lastKnownLocation = null;
  var liveLocationWatchId = null;
  var liveLocationStartPromise = null;
  var liveLocationSubscribers = [];

  // ── Time Helpers ───────────────────────────────────────────

  /** Get current Cambodia time parts. */
  function getCambodiaTime() {
    var ct = new Date(
      new Date().toLocaleString("en-US", { timeZone: PTT_CONFIG.TIMEZONE })
    );
    return { hour: ct.getHours(), minute: ct.getMinutes(), date: ct };
  }

  /** Format 24h + minute → "8:30 PM" */
  function formatTime(hour24, minute) {
    var period = hour24 >= 12 ? "PM" : "AM";
    var h = hour24 % 12 || 12;
    var m = minute.toString().padStart(2, "0");
    return h + ":" + m + " " + period;
  }

  function normalizeId(value) {
    return String(value == null ? "" : value).trim();
  }

  function normalizeScheduleKey(value) {
    return PTT_CONFIG.normalizeScheduleKey(value);
  }

  function getOperationSchedules() {
    return PTT_CONFIG.getOperationSchedules();
  }

  function getStationGroup(station) {
    if (!station || !station.schedule_group_code) return null;
    return PTT_CONFIG.getScheduleGroup(station.schedule_group_code);
  }

  function getDefaultScheduleKey() {
    return PTT_CONFIG.getDefaultScheduleKey
      ? PTT_CONFIG.getDefaultScheduleKey()
      : PTT_CONFIG.DEFAULT_SCHEDULE;
  }

  function isSpecialStatus(value) {
    return !!PTT_CONFIG.SPECIAL_STATUSES[normalizeScheduleKey(value).toLowerCase()];
  }

  function getStationScheduleKey(station) {
    if (!station || typeof station === "string") {
      var directKey = normalizeScheduleKey(station || "");
      return getOperationSchedules()[directKey] ? directKey : getDefaultScheduleKey();
    }

    var explicitScheduleKey = normalizeScheduleKey(station.schedule_key || "");
    if (explicitScheduleKey && getOperationSchedules()[explicitScheduleKey]) {
      return explicitScheduleKey;
    }

    var legacyStatusKey = normalizeScheduleKey(station.status || "");
    if (legacyStatusKey && getOperationSchedules()[legacyStatusKey]) {
      return legacyStatusKey;
    }

    var group = getStationGroup(station);
    var groupScheduleKey = normalizeScheduleKey(group && group.schedule_key);
    if (groupScheduleKey && getOperationSchedules()[groupScheduleKey]) {
      return groupScheduleKey;
    }

    return getDefaultScheduleKey();
  }

  function resolveStationStatus(stationOrStatus) {
    if (typeof stationOrStatus === "string") {
      var rawKey = normalizeScheduleKey(stationOrStatus);
      if (isSpecialStatus(rawKey)) {
        return rawKey.toLowerCase();
      }
      return getOperationSchedules()[rawKey] ? rawKey : getDefaultScheduleKey();
    }

    var station = stationOrStatus || {};
    var rawStatus = normalizeScheduleKey(station.status || "");
    var rawStatusLower = rawStatus.toLowerCase();

    if (PTT_CONFIG.SPECIAL_STATUSES[rawStatusLower]) {
      return rawStatusLower;
    }

    return getStationScheduleKey(station);
  }

  function resolveSchedule(stationOrStatus) {
    var key = resolveStationStatus(stationOrStatus);
    if (PTT_CONFIG.SPECIAL_STATUSES[key.toLowerCase()]) return null;
    return getOperationSchedules()[key] || getOperationSchedules()[getDefaultScheduleKey()];
  }

  function isStationOpen(stationOrStatus) {
    var key = resolveStationStatus(stationOrStatus);
    if (PTT_CONFIG.SPECIAL_STATUSES[key.toLowerCase()]) return false;

    var schedule = resolveSchedule(stationOrStatus);
    if (!schedule) return false;
    if (schedule.is24h) return true;

    var t = getCambodiaTime();
    var afterOpen =
      t.hour > schedule.openHour ||
      (t.hour === schedule.openHour && t.minute >= schedule.openMinute);
    var beforeClose =
      t.hour < schedule.closeHour ||
      (t.hour === schedule.closeHour && t.minute < schedule.closeMinute);
    return afterOpen && beforeClose;
  }

  /** Marker icon URL based on station status & time. */
  function getIconUrl(stationOrStatus) {
    var key = resolveStationStatus(stationOrStatus);
    var special = PTT_CONFIG.SPECIAL_STATUSES[key.toLowerCase()];
    if (special) return special.iconUrl;
    return isStationOpen(stationOrStatus)
      ? PTT_CONFIG.IMAGE_BASE_URL + "61.png"
      : PTT_CONFIG.IMAGE_BASE_URL + "time_close1.png";
  }

  /** Badge / status info for route-info section. */
  function getStatusInfo(stationOrStatus) {
    var key = resolveStationStatus(stationOrStatus);
    var special = PTT_CONFIG.SPECIAL_STATUSES[key.toLowerCase()];
    if (special) {
      return {
        iconClass: special.iconClass,
        badgeClass: special.badgeClass,
        displayText: special.displayText,
      };
    }

    var schedule = resolveSchedule(stationOrStatus);
    if (schedule && schedule.is24h) {
      return {
        iconClass: "fa-gas-pump",
        badgeClass: "bg-success text-white",
        displayText: schedule.label || "Open 24h",
      };
    }

    if (isStationOpen(stationOrStatus)) {
      return {
        iconClass: "fa-gas-pump",
        badgeClass: "bg-success text-white",
        displayText: "Open until " + formatTime(schedule.closeHour, schedule.closeMinute),
      };
    }

    return {
      iconClass: "fa-times-circle",
      badgeClass: "bg-danger text-white",
      displayText: "Closed",
    };
  }

  // ── Geolocation ────────────────────────────────────────────

  function cloneLocation(location) {
    return location
      ? {
          lat: location.lat,
          lng: location.lng,
          accuracy: location.accuracy,
          timestamp: location.timestamp,
        }
      : null;
  }

  function buildGeolocationOptions(overrides) {
    var base = PTT_CONFIG.GEOLOCATION_OPTIONS || {};
    var extra = overrides || {};
    return {
      enableHighAccuracy:
        typeof extra.enableHighAccuracy === "boolean"
          ? extra.enableHighAccuracy
          : !!base.enableHighAccuracy,
      timeout: Number(extra.timeout != null ? extra.timeout : base.timeout || 5000),
      maximumAge: Number(
        extra.maximumAge != null ? extra.maximumAge : base.maximumAge || 0
      ),
    };
  }

  function positionToLocation(pos) {
    return {
      lat: pos.coords.latitude,
      lng: pos.coords.longitude,
      accuracy: pos.coords.accuracy,
      timestamp: pos.timestamp || Date.now(),
    };
  }

  function hasMeaningfulLocationChange(nextLocation) {
    if (!lastKnownLocation) return true;

    var movedMeters =
      calculateDistance(
        lastKnownLocation.lat,
        lastKnownLocation.lng,
        nextLocation.lat,
        nextLocation.lng
      ) * 1000;

    return movedMeters >= (PTT_CONFIG.LIVE_LOCATION_MIN_DISTANCE_METERS || 0);
  }

  function notifyLiveLocationSubscribers(location) {
    var safeLocation = cloneLocation(location);
    liveLocationSubscribers.slice().forEach(function (callback) {
      try {
        callback(safeLocation);
      } catch (error) {
        console.error("Live location subscriber error:", error);
      }
    });
  }

  function getCurrentLocation(options) {
    var resolvedOptions = options || {};
    if (resolvedOptions.preferCached !== false && lastKnownLocation) {
      return Promise.resolve(cloneLocation(lastKnownLocation));
    }

    return new Promise(function (resolve, reject) {
      if ("geolocation" in navigator) {
        navigator.geolocation.getCurrentPosition(
          function (pos) {
            lastKnownLocation = positionToLocation(pos);
            resolve(cloneLocation(lastKnownLocation));
          },
          function (err) {
            reject(err);
          },
          buildGeolocationOptions(resolvedOptions)
        );
      } else {
        reject(new Error("Geolocation is not supported by your browser."));
      }
    });
  }

  function startLocationWatch(options) {
    if (!("geolocation" in navigator)) {
      return Promise.reject(new Error("Geolocation is not supported by your browser."));
    }

    if (liveLocationWatchId !== null) {
      if (lastKnownLocation) {
        return Promise.resolve(cloneLocation(lastKnownLocation));
      }
      if (liveLocationStartPromise) {
        return liveLocationStartPromise;
      }
    }

    liveLocationStartPromise = new Promise(function (resolve, reject) {
      var settled = false;

      liveLocationWatchId = navigator.geolocation.watchPosition(
        function (pos) {
          var nextLocation = positionToLocation(pos);
          var shouldNotify = hasMeaningfulLocationChange(nextLocation);

          lastKnownLocation = nextLocation;

          if (!settled) {
            settled = true;
            resolve(cloneLocation(nextLocation));
            liveLocationStartPromise = null;
          }

          if (shouldNotify) {
            notifyLiveLocationSubscribers(nextLocation);
          }
        },
        function (err) {
          if (!settled) {
            settled = true;
            if (liveLocationWatchId !== null) {
              navigator.geolocation.clearWatch(liveLocationWatchId);
              liveLocationWatchId = null;
            }
            liveLocationStartPromise = null;
            reject(err);
            return;
          }

          console.error("Live location watch error:", err);
        },
        buildGeolocationOptions(options)
      );
    });

    return liveLocationStartPromise;
  }

  function stopLocationWatch() {
    if (liveLocationWatchId !== null && "geolocation" in navigator) {
      navigator.geolocation.clearWatch(liveLocationWatchId);
    }
    liveLocationWatchId = null;
    liveLocationStartPromise = null;
  }

  function subscribeToLocationUpdates(callback) {
    if (typeof callback !== "function") {
      return function () {};
    }

    liveLocationSubscribers.push(callback);

    if (lastKnownLocation) {
      callback(cloneLocation(lastKnownLocation));
    }

    return function unsubscribe() {
      liveLocationSubscribers = liveLocationSubscribers.filter(function (subscriber) {
        return subscriber !== callback;
      });
    };
  }

  function getLastKnownLocation() {
    return cloneLocation(lastKnownLocation);
  }

  // ── Distance ───────────────────────────────────────────────

  /** Haversine distance in km. */
  function calculateDistance(lat1, lng1, lat2, lng2) {
    var R = 6371;
    var dLat = ((lat2 - lat1) * Math.PI) / 180;
    var dLng = ((lng2 - lng1) * Math.PI) / 180;
    var a =
      Math.sin(dLat / 2) * Math.sin(dLat / 2) +
      Math.cos((lat1 * Math.PI) / 180) *
        Math.cos((lat2 * Math.PI) / 180) *
        Math.sin(dLng / 2) *
        Math.sin(dLng / 2);
    return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
